vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 d = uTexSize.zw*6;
    vec3 dx = ( GetBlur1(vUv+vec2(1,0)*d)-GetBlur1(vUv-vec2(1,0)*d) );
    vec3 dy = ( GetBlur1(vUv+vec2(0,1)*d)-GetBlur1(vUv-vec2(0,1)*d) );
    vec2 uv_y = vUv-vec2(dx.y,dy.y)*0.6;
    vec2 uv_x = vUv+vec2(dx.x,dy.x)*0.2;

ret = mix(vec3(0.4,0.5,1)*max(0,1-length((uv_y-0.5)*uAspect.xy)*2 -0.2+GetPixel(vUv).z*0.2)
           + GetPixel(vUv).x,
           mix(vec3(2,2,1),vec3(2,-1,-2),GetPixel(vUv).z), GetBlur1(uv_x).y*0.35);
//ret =  GetPixel(vUv);

  fragColor = ret;
